Node* traverse_or_create(Node* root, const vector<string>& parts, bool create) {
    Node* node = root;
    for (const auto& part : parts) {
        auto it = node->children.find(part);
        if (it == node->children.end()) {
            if (!create) return nullptr;
            node->children[part] = new Node();
            it = node->children.find(part);
        }
        node = it->second;
    }
    return node;
}

